# Category: serverless_security

from flask import Flask, jsonify, request
import os

app = Flask(__name__)

@app.after_request
def after_request(response):
    response.headers.add('Access-Control-Allow-Origin', '*')
    response.headers.add('Access-Control-Allow-Headers', 'Content-Type,Authorization')
    response.headers.add('Access-Control-Allow-Methods', 'GET,PUT,POST,DELETE,OPTIONS')
    return response

@app.route('/api/health', methods=['GET', 'OPTIONS'])
def health_check():
    if request.method == 'OPTIONS':
        return jsonify({}), 200
    return jsonify({'status': 'healthy'}), 200

@app.route('/api/data', methods=['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'])
def handle_data():
    if request.method == 'OPTIONS':
        return jsonify({}), 200
    
    try:
        if request.method == 'GET':
            return jsonify({'message': 'GET request received'}), 200
        elif request.method == 'POST':
            return jsonify({'message': 'POST request received', 'data': request.get_json()}), 201
        elif request.method == 'PUT':
            return jsonify({'message': 'PUT request received', 'data': request.get_json()}), 200
        elif request.method == 'DELETE':
            return jsonify({'message': 'DELETE request received'}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 400

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=int(os.environ.get('PORT', 8080)))